	count := pqc.namespacePolicies[namespace]
	if count >= pqc.maxPerNamespace {
		return fmt.Errorf("policy quota exceeded for namespace %q: current=%d, max=%d",
			namespace, count, pqc.maxPerNamespace)
	}

	return nil
}

// GetNamespacePolicyCounts returns a copy of the current policy counts per namespace.
